import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic();

async function classify(feedback: string): Promise<'positive'|'negative'|'neutral'> {
  const r = await client.messages.create({
    model: 'claude-haiku-3-5-20241022',
    max_tokens: 10,
    temperature: 0,
    messages: [{ role: 'user', content: `Classify as one word (positive, negative, or neutral):\n${feedback}` }]
  });
  const t = r.content[0].type === 'text' ? r.content[0].text.trim().toLowerCase() : 'neutral';
  return t === 'positive' || t === 'negative' ? t : 'neutral';
}

