exercises.solution:
import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic();

type ToolHandler = (name: string, input: any) => Promise<string>;

async function runWithTools(
  prompt: string,
  tools: Anthropic.Tool[],
  handler: ToolHandler
): Promise<string> {
  const messages: Anthropic.MessageParam[] = [{ role: 'user', content: prompt }];
  const r = await client.messages.create({ model: 'claude-sonnet-4-20250514', max_tokens: 1024, tools, messages });
  if (r.stop_reason === 'tool_use') {
    const tb = r.content.find(b => b.type === 'tool_use')!;
    const result = await handler(tb.name, tb.input);
    messages.push({ role: 'assistant', content: r.content });
    messages.push({ role: 'user', content: [{ type: 'tool_result', tool_use_id: tb.id, content: result }] });
    const f = await client.messages.create({ model: 'claude-sonnet-4-20250514', max_tokens: 1024, tools, messages });
    const txt = f.content.find(b => b.type === 'text');
    return txt ? txt.text : '';
  }
  const txt = r.content.find(b => b.type === 'text');
  return txt ? txt.text : '';
}

