exercises.solution:
import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic();

async function agentLoop(
  prompt: string,
  tools: Anthropic.Tool[],
  handler: (name: string, input: any) => Promise<string>
): Promise<string> {
  const messages: Anthropic.MessageParam[] = [{ role: 'user', content: prompt }];
  while (true) {
    const r = await client.messages.create({ model: 'claude-sonnet-4-20250514', max_tokens: 4096, tools, messages });
    if (r.stop_reason !== 'tool_use') {
      const t = r.content.find(b => b.type === 'text');
      return t ? t.text : '';
    }
    messages.push({ role: 'assistant', content: r.content });
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const b of r.content) {
      if (b.type === 'tool_use') {
        const res = await handler(b.name, b.input);
        results.push({ type: 'tool_result', tool_use_id: b.id, content: res });
      }
    }
    messages.push({ role: 'user', content: results });
  }
}

