import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic();

async function robustAgent(
  prompt: string,
  tools: Anthropic.Tool[],
  exec: (name:string, input:any) => Promise<string>
): Promise<string> {
  const msgs: Anthropic.MessageParam[] = [{ role: 'user', content: prompt }];
  while (true) {
    const r = await client.messages.create({ model: 'claude-sonnet-4-20250514', max_tokens: 4096, tools, messages: msgs });
    if (r.stop_reason !== 'tool_use') {
      const t = r.content.find(b => b.type === 'text');
      return t ? t.text : '';
    }
    msgs.push({ role: 'assistant', content: r.content });
    const calls = r.content.filter((b): b is Anthropic.ToolUseBlock => b.type === 'tool_use');
    const results = await Promise.all(calls.map(async tc => {
      try {
        return { type: 'tool_result' as const, tool_use_id: tc.id, content: await exec(tc.name, tc.input) };
      } catch (e: any) {
        return { type: 'tool_result' as const, tool_use_id: tc.id, content: `Error: ${e.message}`, is_error: true };
      }
    }));
    msgs.push({ role: 'user', content: results });
  }
}

