import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic();

async function streamingAgent(
  prompt: string,
  tools: Anthropic.Tool[],
  exec: (name:string, input:any) => Promise<string>,
  onText: (t:string) => void
): Promise<string> {
  const msgs: Anthropic.MessageParam[] = [{ role: 'user', content: prompt }];
  let fullText = '';
  while (true) {
    const stream = client.messages.stream({ model: 'claude-sonnet-4-20250514', max_tokens: 4096, tools, messages: msgs });
    stream.on('text', (d) => { onText(d); fullText += d; });
    const msg = await stream.finalMessage();
    if (msg.stop_reason !== 'tool_use') return fullText;
    msgs.push({ role: 'assistant', content: msg.content });
    const calls = msg.content.filter((b): b is Anthropic.ToolUseBlock => b.type === 'tool_use');
    const results = await Promise.all(calls.map(async tc => ({
      type: 'tool_result' as const, tool_use_id: tc.id,
      content: await exec(tc.name, tc.input)
    })));
    msgs.push({ role: 'user', content: results });
  }
}

