import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic();

async function extractDate(text: string): Promise<string> {
  const tools: Anthropic.Tool[] = [{ name: 'output_date', description: 'Output the extracted date.', input_schema: { type: 'object', properties: { date: { type: 'string', description: 'Date in YYYY-MM-DD format' } }, required: ['date'] } }];
  let feedback = '';
  for (let i = 0; i < 3; i++) {
    const prompt = feedback ? `${text}\n\nError: ${feedback}` : text;
    const r = await client.messages.create({ model: 'claude-sonnet-4-20250514', max_tokens: 256, tools, tool_choice: { type: 'tool', name: 'output_date' }, messages: [{ role: 'user', content: `Extract the date:\n${prompt}` }] });
    const d = (r.content.find(b => b.type === 'tool_use')!.input as any).date;
    if (/^\d{4}-\d{2}-\d{2}$/.test(d) && !isNaN(Date.parse(d))) return d;
    feedback = `"${d}" is not valid YYYY-MM-DD. Try again.`;
  }
  throw new Error('Failed to extract valid date after 3 retries');
}

