import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic();

async function withValidation<T>(
  prompt: string,
  tool: Anthropic.Tool,
  validate: (data: unknown) => { ok: true; data: T } | { ok: false; error: string },
  retries = 3
): Promise<T> {
  let msg = prompt;
  for (let i = 0; i < retries; i++) {
    const r = await client.messages.create({
      model: 'claude-sonnet-4-20250514', max_tokens: 1024,
      tools: [tool], tool_choice: { type: 'tool', name: tool.name },
      messages: [{ role: 'user', content: msg }]
    });
    const raw = r.content.find(b => b.type === 'tool_use')!.input;
    const result = validate(raw);
    if (result.ok) return result.data;
    msg = `${prompt}\n\nValidation error: ${result.error}. Please fix.`;
  }
  throw new Error(`Validation failed after ${retries} retries`);
}

