import { z } from 'zod';
import { zodToJsonSchema } from 'zod-to-json-schema';
import Anthropic from '@anthropic-ai/sdk';

const BlogPostSchema = z.object({
  title: z.string().min(1).max(200),
  content: z.string().min(50),
  tags: z.array(z.string()).min(1).max(10),
  publishDate: z.string().regex(/^\d{4}-\d{2}-\d{2}$/)
});

type BlogPost = z.infer<typeof BlogPostSchema>;
const client = new Anthropic();

async function extractBlogPost(text: string): Promise<BlogPost> {
  const tool: Anthropic.Tool = {
    name: 'output_post',
    description: 'Output structured blog post data.',
    input_schema: zodToJsonSchema(BlogPostSchema) as any
  };
  const r = await client.messages.create({
    model: 'claude-sonnet-4-20250514', max_tokens: 2048,
    tools: [tool], tool_choice: { type: 'tool', name: 'output_post' },
    messages: [{ role: 'user', content: text }]
  });
  const data = r.content.find(b => b.type === 'tool_use')!.input;
