exercises.solution:
import { z, ZodSchema, ZodError } from 'zod';
import { zodToJsonSchema } from 'zod-to-json-schema';
import Anthropic from '@anthropic-ai/sdk';

async function zodExtract<T>(
  client: Anthropic,
  prompt: string,
  schema: ZodSchema<T>,
  toolName: string
): Promise<T> {
  const tool: Anthropic.Tool = { name: toolName, description: 'Output structured data.', input_schema: zodToJsonSchema(schema) as any };
  let msg = prompt;
  for (let i = 0; i < 3; i++) {
    const r = await client.messages.create({
      model: 'claude-sonnet-4-20250514', max_tokens: 2048,
      tools: [tool], tool_choice: { type: 'tool', name: toolName },
      messages: [{ role: 'user', content: msg }]
    });
    const raw = r.content.find(b => b.type === 'tool_use')!.input;
    try { return schema.parse(raw); }
    catch (e) {
      if (e instanceof ZodError) {
        const issues = e.issues.map(i => `${i.path.join('.')}: ${i.message}`).join('; ');
        msg = `${prompt}\n\nValidation errors: ${issues}. Fix these fields.`;
      } else throw e;
    }
  }
  throw new Error('Zod validation failed after 3 retries');
}

