import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic();

async function classifyTicket(text: string): Promise<'bug'|'feature'|'question'> {
  const r = await client.messages.create({
    model: 'claude-haiku-3-5-20241022', max_tokens: 10, temperature: 0,
    messages: [{ role: 'user', content: `Classify as bug, feature, or question (one word):\n${text}` }]
  });
  const t = (r.content[0] as any).text.trim().toLowerCase();
  return t === 'bug' || t === 'feature' ? t : 'question';
}

const schemas: Record<string, any> = {
  bug: { type: 'object', properties: { severity: { type: 'string', enum: ['low','medium','high','critical'] }, steps: { type: 'array', items: { type: 'string' } }, expected: { type: 'string' }, actual: { type: 'string' } }, required: ['severity','steps','expected','actual'] },
  feature: { type: 'object', properties: { title: { type: 'string' }, useCase: { type: 'string' }, priority: { type: 'string' } }, required: ['title','useCase'] },
  question: { type: 'object', properties: { topic: { type: 'string' }, question: { type: 'string' } }, required: ['topic','question'] }
};

async function processTicket(ticket: string) {
  const type = await classifyTicket(ticket);
  const tool: Anthropic.Tool = { name: 'extract', description: `Extract ${type} data`, input_schema: schemas[type] };
  const r = await client.messages.create({
    model: 'claude-sonnet-4-20250514', max_tokens: 1024,
    tools: [tool], tool_choice: { type: 'tool', name: 'extract' },
    messages: [{ role: 'user', content: ticket }]
  });
  return { type, data: r.content.find(b => b.type === 'tool_use')!.input };
}

