exercises.solution:
async function batchExtract<T>(
  docs: string[],
  extractOne: (doc: string) => Promise<T>,
  concurrency: number
): Promise<T[]> {
  const results: T[] = new Array(docs.length);
  let idx = 0;
  async function worker() {
    while (idx < docs.length) {
      const i = idx++;
      results[i] = await extractOne(docs[i]);
    }
  }
  await Promise.all(Array.from({ length: concurrency }, () => worker()));
  return results;
}

