import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic();
type Msg = { role: 'user'|'assistant'; content: string };

async function compressMemory(messages: Msg[], maxMessages: number): Promise<Msg[]> {
  if (messages.length <= maxMessages) return messages;
  const old = messages.slice(0, messages.length - maxMessages);
  const recent = messages.slice(messages.length - maxMessages);
  const history = old.map(m => `${m.role}: ${m.content}`).join('\n');
  const r = await client.messages.create({
    model: 'claude-haiku-3-5-20241022', max_tokens: 500, temperature: 0,
    messages: [{ role: 'user', content: `Summarize key facts and decisions:\n\n${history}` }]
  });
  const summary = r.content[0].type === 'text' ? r.content[0].text : '';
  return [
    { role: 'user', content: `[Previous conversation: ${summary}]` },
    { role: 'assistant', content: 'Understood, I have the context.' },
    ...recent
  ];
}

