async function runPipeline(
  agents: Agent[],
  input: string,
  onStage?: (i: number, output: string) => void
): Promise<string> {
  let current = input;
  for (let i = 0; i < agents.length; i++) {
    const result = await run(agents[i], current);
    current = result.output;
    onStage?.(i, current);
  }
  return current;
}

