import { Agent, run } from '@anthropic-ai/agent-sdk';

async function fanOutMerge(
  agents: Agent[], input: string, merger: Agent
): Promise<{output:string;failures:string[]}> {
  const results = await Promise.allSettled(agents.map(a => run(a, input)));
  const successes: string[] = [];
  const failures: string[] = [];
  results.forEach((r, i) => {
    if (r.status === 'fulfilled') successes.push(`${agents[i].name}: ${r.value.output}`);
    else failures.push(`${agents[i].name}: ${r.reason?.message || 'Error'}`);
  });
  const merged = await run(merger, successes.join('\n\n'));
  return { output: merged.output, failures };
}

