type ToolCall = { name: string; input: any };

function createTestHarness(mocks: Record<string, (input: any) => string>) {
  const calls: ToolCall[] = [];
  return {
    handler: async (name: string, input: any) => {
      calls.push({ name, input });
      return mocks[name]?.(input) || `Mock: no handler for ${name}`;
    },
    getCalls: () => [...calls],
    assertSequence(expected: string[]) {
      const actual = calls.map(c => c.name);
      if (JSON.stringify(actual) !== JSON.stringify(expected))
        throw new Error(`Expected [${expected}] got [${actual}]`);
    }
  };
}

