    let totalIn = 0, totalOut = 0;
    const perAgent: Record<string, any> = {};
    for (const [name, u] of this.usage) {
      totalIn += u.input; totalOut += u.output;
      perAgent[name] = { ...u, cost: (u.input * 3 + u.output * 15) / 1_000_000 };
    }
    return { totalIn, totalOut, totalCost: (totalIn * 3 + totalOut * 15) / 1_000_000, perAgent };
  }
}

