class CircuitBreaker {
  private failures = 0;
  private lastFailure = 0;
  private isOpen = false;

  constructor(private threshold: number, private resetMs: number) {}

  async call<T>(fn: () => Promise<T>): Promise<T> {
    if (this.isOpen) {
      if (Date.now() - this.lastFailure > this.resetMs) this.isOpen = false;
      else throw new Error('Circuit breaker open');
    }
    try {
      const r = await fn();
      this.failures = 0;
      return r;
    } catch (e) {
      this.failures++;
      this.lastFailure = Date.now();
      if (this.failures >= this.threshold) this.isOpen = true;
      throw e;
    }
  }
}

