async function batchClassify(items: string[]): Promise<Map<string,string>> {
  const batch = await client.messages.batches.create({
    requests: items.map((item, i) => ({
      custom_id: `item-${i}`,
      params: { model: 'claude-haiku-3-5-20241022', max_tokens: 50, temperature: 0, messages: [{ role: 'user', content: `Classify (positive/negative/neutral): ${item}` }] }
    }))
  });
  let status = await client.messages.batches.retrieve(batch.id);
  while (status.processing_status !== 'ended') {
    await new Promise(r => setTimeout(r, 60000));
    status = await client.messages.batches.retrieve(batch.id);
  }
  const results = new Map<string, string>();
  for await (const r of client.messages.batches.results(batch.id)) {
    if (r.result.type === 'succeeded') {
      const t = r.result.message.content[0];
      results.set(r.custom_id, t.type === 'text' ? t.text.trim().toLowerCase() : '');
    }
  }
  return results;
}

