import Anthropic from '@anthropic-ai/sdk';
const client = new Anthropic();

async function robustBatch(items: {id:string;prompt:string}[], retries = 2): Promise<{ok:Map<string,string>;failed:string[]}> {
  const ok = new Map<string, string>();
  let pending = items;
  for (let attempt = 0; attempt <= retries && pending.length > 0; attempt++) {
    const batch = await client.messages.batches.create({
      requests: pending.map(i => ({ custom_id: i.id, params: { model: 'claude-haiku-3-5-20241022', max_tokens: 256, messages: [{ role: 'user', content: i.prompt }] } }))
    });
    let s = await client.messages.batches.retrieve(batch.id);
    while (s.processing_status !== 'ended') { await new Promise(r => setTimeout(r, 60000)); s = await client.messages.batches.retrieve(batch.id); }
    const failedIds = new Set<string>();
    for await (const r of client.messages.batches.results(batch.id)) {
      if (r.result.type === 'succeeded') { const t = r.result.message.content[0]; ok.set(r.custom_id, t.type === 'text' ? t.text : ''); }
      else failedIds.add(r.custom_id);
    }
    pending = pending.filter(i => failedIds.has(i.id));
  }
  return { ok, failed: pending.map(i => i.id) };
}

