exercises.solution:
class TokenBucket {
  private available: number;
  private lastRefill: number;
  constructor(private tokensPerMinute: number) {
    this.available = tokensPerMinute;
    this.lastRefill = Date.now();
  }
  private refill() {
    const elapsed = (Date.now() - this.lastRefill) / 60000;
    this.available = Math.min(this.tokensPerMinute, this.available + elapsed * this.tokensPerMinute);
    this.lastRefill = Date.now();
  }
  async consume(tokens: number): Promise<void> {
    this.refill();
    while (this.available < tokens) {
      const waitMs = ((tokens - this.available) / this.tokensPerMinute) * 60000;
      await new Promise(r => setTimeout(r, Math.max(100, waitMs)));
      this.refill();
    }
    this.available -= tokens;
  }
}

