import crypto from 'crypto';

class ResponseCache {
  private cache = new Map<string, { value: string; expires: number }>();
  constructor(private ttlMs: number) {}
  private hash(p: any) { return crypto.createHash('sha256').update(JSON.stringify(p)).digest('hex'); }
  get(params: any): string | null {
    const e = this.cache.get(this.hash(params));
    if (!e || Date.now() > e.expires) return null;
    return e.value;
  }
  set(params: any, value: string) {
    this.cache.set(this.hash(params), { value, expires: Date.now() + this.ttlMs });
  }
}

