class CostTracker {
  private spend = new Map<string, number>();
  constructor(private budget: number) {}

  record(userId: string, inTokens: number, outTokens: number, model: string) {
    const rates: Record<string, [number,number]> = { 'claude-haiku-3-5-20241022': [0.25,1.25], 'claude-sonnet-4-20250514': [3,15], 'claude-opus-4-20250514': [15,75] };
    const [ir, or] = rates[model] || [3, 15];
    const cost = (inTokens * ir + outTokens * or) / 1e6;
    const total = (this.spend.get(userId) || 0) + cost;
    this.spend.set(userId, total);
    return { cost, total, over: total > this.budget };
  }

  getSpend(userId: string) { return this.spend.get(userId) || 0; }
}

