import React, { useState, useRef, useEffect } from 'react';
import Vapi from '@vapi-ai/web';

function VoiceAgent({ assistantId }: { assistantId: string }) {
  const [status, setStatus] = useState<'idle'|'connecting'|'active'>('idle');
  const vapiRef = useRef<Vapi | null>(null);
  useEffect(() => {
    const key = process.env.NEXT_PUBLIC_VAPI_KEY;
    if (!key) throw new Error('VAPI key missing');
    const vapi = new Vapi(key);
    vapi.on('call-start', () => setStatus('active'));
    vapi.on('call-end', () => setStatus('idle'));
    vapiRef.current = vapi;
    return () => { vapi.stop(); };
  }, []);
  return (
    <div>
      <p>Status: {status}</p>
      {status === 'idle'
        ? <button onClick={() => { setStatus('connecting'); vapiRef.current?.start({ assistantId }); }}>Call</button>
        : <button onClick={() => { vapiRef.current?.stop(); setStatus('idle'); }}>End</button>}
    </div>
  );
}

