  book_consultation: async ({ date, time, name, caseType }) => JSON.stringify({ confirmed: true, id: 'C-' + Date.now(), date, time, name, caseType }),
  lookup_case_type: async ({ description }) => {
    const types: Record<string,string> = { car:'auto_accident', slip:'premises_liability', work:'workers_comp', medical:'malpractice' };
    const match = Object.entries(types).find(([k]) => description.toLowerCase().includes(k));
    return JSON.stringify({ caseType: match ? match[1] : 'general_pi' });
  }
};

app.post('/webhook', async (req, res) => {
  const { message } = req.body;
  if (message.type === 'function-call') {
    const h = tools[message.functionCall.name];
    return res.json({ result: h ? await h(message.functionCall.parameters) : '{"error":"unknown"}' });
  }
  if (message.type === 'end-of-call-report') {
    console.log(`Call ${message.call.id} ended. Duration: ${message.call.duration}s`);
  }
  res.json({});
});
app.listen(3000);

