type Call = { id:string; assistantId:string; duration:number; tools:string[]; booked:boolean; ts:string };

class VoiceMetrics {
  private calls: Call[] = [];
  record(c: Call) { this.calls.push(c); }
  summary(since?: Date) {
    const f = since ? this.calls.filter(c => new Date(c.ts) >= since) : this.calls;
    const total = f.length;
    const booked = f.filter(c => c.booked).length;
    const durations = f.map(c => c.duration);
    const toolUsage: Record<string, number> = {};
    f.forEach(c => c.tools.forEach(t => { toolUsage[t] = (toolUsage[t] || 0) + 1; }));
    return {
      totalCalls: total,
      conversion: total > 0 ? (booked / total * 100).toFixed(1) + '%' : '0%',
      avgDuration: total > 0 ? Math.round(durations.reduce((a,b) => a+b, 0) / total) : 0,
      toolUsage
    };
  }
}
